  // QuickSelect O(n) avg
  function qs(l,r){
    const pivot=nums[r];let p=l;
    for(let i=l;i<r;i++)if(nums[i]<=pivot){[nums[p],nums[i]]=[nums[i],nums[p]];p++;}
    [nums[p],nums[r]]=[nums[r],nums[p]];
    if(p===nums.length-k)return nums[p];
    if(p<nums.length-k)return qs(p+1,r);
    return qs(l,p-1);
  }
  return qs(0,nums.length-1);
